(function() {
  'use strict';

  if (window.__twitterMediaDLActive) return;
  window.__twitterMediaDLActive = true;

  var PROCESSED_ATTR = 'data-ba-media-dl';
  // id_str -> { photos: [url], videos: [{ url }] }
  var mediaByTweet = Object.create(null);

  /* ── Styles ── */
  var STYLES = document.createElement('style');
  STYLES.textContent = [
    '.ba-dl-btn{display:inline-flex;align-items:center;gap:4px;padding:4px 10px;margin:4px;font-size:13px;font-weight:500;color:#1d9bf0;background:transparent;border:1px solid #1d9bf0;border-radius:9999px;cursor:pointer;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",Roboto,sans-serif;transition:all .15s}',
    '.ba-dl-btn:hover{background:#1d9bf0;color:#fff}',
    '.ba-dl-btn svg{width:14px;height:14px;fill:currentColor}',
    '.ba-dl-bar{display:flex;flex-wrap:wrap;align-items:center;padding:4px 0}'
  ].join('\n');
  (document.head || document.documentElement).appendChild(STYLES);

  var DL_ICON = '<svg viewBox="0 0 24 24"><path d="M12 15.575l-4.95-4.95 1.414-1.414L11 11.747V3h2v8.747l2.536-2.536 1.414 1.414L12 15.575zM5 19h14v-4h2v5a1 1 0 01-1 1H4a1 1 0 01-1-1v-5h2v4z"/></svg>';

  /* ── Store-only ZIP builder (no compression) ── */
  function crc32(buf) {
    var table = new Uint32Array(256);
    for (var i = 0; i < 256; i++) {
      var c = i;
      for (var j = 0; j < 8; j++) c = (c & 1) ? (0xEDB88320 ^ (c >>> 1)) : (c >>> 1);
      table[i] = c;
    }
    var crc = 0xFFFFFFFF;
    for (var k = 0; k < buf.length; k++) crc = table[(crc ^ buf[k]) & 0xFF] ^ (crc >>> 8);
    return (crc ^ 0xFFFFFFFF) >>> 0;
  }

  function buildZip(files) {
    var localHeaders = [];
    var centralHeaders = [];
    var offset = 0;
    var encoder = new TextEncoder();
    for (var i = 0; i < files.length; i++) {
      var nameBytes = encoder.encode(files[i].name);
      var data = new Uint8Array(files[i].data);
      var checksum = crc32(data);
      var localHeader = new Uint8Array(30 + nameBytes.length);
      var lv = new DataView(localHeader.buffer);
      lv.setUint32(0, 0x04034b50, true);
      lv.setUint16(4, 20, true);
      lv.setUint16(8, 0, true);
      lv.setUint32(14, checksum, true);
      lv.setUint32(18, data.length, true);
      lv.setUint32(22, data.length, true);
      lv.setUint16(26, nameBytes.length, true);
      localHeader.set(nameBytes, 30);
      localHeaders.push(localHeader);
      localHeaders.push(data);
      var centralHeader = new Uint8Array(46 + nameBytes.length);
      var cv = new DataView(centralHeader.buffer);
      cv.setUint32(0, 0x02014b50, true);
      cv.setUint16(4, 20, true);
      cv.setUint16(6, 20, true);
      cv.setUint16(12, 0, true);
      cv.setUint32(16, checksum, true);
      cv.setUint32(20, data.length, true);
      cv.setUint32(24, data.length, true);
      cv.setUint16(28, nameBytes.length, true);
      cv.setUint32(42, offset, true);
      centralHeader.set(nameBytes, 46);
      centralHeaders.push(centralHeader);
      offset += localHeader.length + data.length;
    }
    var centralSize = centralHeaders.reduce(function(s, h) { return s + h.length; }, 0);
    var endRecord = new Uint8Array(22);
    var ev = new DataView(endRecord.buffer);
    ev.setUint32(0, 0x06054b50, true);
    ev.setUint16(8, files.length, true);
    ev.setUint16(10, files.length, true);
    ev.setUint32(12, centralSize, true);
    ev.setUint32(16, offset, true);
    var parts = localHeaders.concat(centralHeaders, [endRecord]);
    var totalSize = parts.reduce(function(s, p) { return s + p.length; }, 0);
    var result = new Uint8Array(totalSize);
    var pos = 0;
    for (var p = 0; p < parts.length; p++) {
      result.set(parts[p], pos);
      pos += parts[p].length;
    }
    return new Blob([result], { type: 'application/zip' });
  }

  /* ── Upgrade a pbs.twimg.com image to full resolution (name=orig, keep format) ── */
  function toOrig(url) {
    try {
      var u = new URL(url, location.href);
      if (u.hostname.indexOf('twimg.com') === -1) return url;
      if (u.searchParams.has('format')) {
        u.searchParams.set('name', 'orig');
        return u.href;
      }
      var m = url.match(/\/media\/([^/.?]+)\.(jpg|jpeg|png|webp)/i);
      if (m) {
        var fmt = m[2].toLowerCase();
        if (fmt === 'jpeg') fmt = 'jpg';
        return 'https://pbs.twimg.com/media/' + m[1] + '?format=' + fmt + '&name=orig';
      }
      return url;
    } catch (_) {
      return url;
    }
  }

  /* ── Harvest media URLs from X's own GraphQL JSON. The <video> element's src is
       a blob:/MediaSource URL that cannot be downloaded; the real video.twimg.com
       MP4 files live in legacy.extended_entities.media[].video_info.variants[]. ── */
  function pickBestVariant(variants) {
    var best = null;
    (variants || []).forEach(function(v) {
      if (v && v.content_type === 'video/mp4' && v.url) {
        var br = typeof v.bitrate === 'number' ? v.bitrate : 0;
        if (!best || br > best.bitrate) best = { url: v.url, bitrate: br };
      }
    });
    return best;
  }

  function harvest(obj, seen) {
    if (!obj || typeof obj !== 'object') return;
    if (seen.has(obj)) return;
    seen.add(obj);
    if (obj.id_str && obj.extended_entities && Array.isArray(obj.extended_entities.media)) {
      var entry = mediaByTweet[obj.id_str] || { photos: [], videos: [] };
      obj.extended_entities.media.forEach(function(m) {
        if (m.type === 'photo' && m.media_url_https) {
          var u = toOrig(m.media_url_https);
          if (entry.photos.indexOf(u) === -1) entry.photos.push(u);
        } else if ((m.type === 'video' || m.type === 'animated_gif') && m.video_info) {
          var best = pickBestVariant(m.video_info.variants);
          if (best) entry.videos.push({ url: best.url });
        }
      });
      mediaByTweet[obj.id_str] = entry;
    }
    if (Array.isArray(obj)) {
      for (var i = 0; i < obj.length; i++) harvest(obj[i], seen);
    } else {
      for (var k in obj) {
        if (Object.prototype.hasOwnProperty.call(obj, k)) harvest(obj[k], seen);
      }
    }
  }

  function ingest(text) {
    if (!text || text.indexOf('extended_entities') === -1) return;
    try { harvest(JSON.parse(text), new WeakSet()); } catch (_) {}
  }

  /* ── Patch fetch + XHR to read X's already-authenticated GraphQL responses ── */
  var GQL_RE = /\/(graphql|api)\//;

  var origFetch = window.fetch;
  if (typeof origFetch === 'function') {
    window.fetch = function() {
      var p = origFetch.apply(this, arguments);
      try {
        p.then(function(resp) {
          if (resp && GQL_RE.test(resp.url || '')) {
            resp.clone().text().then(ingest).catch(function() {});
          }
        }, function() {});
      } catch (_) {}
      return p;
    };
  }

  var origOpen = XMLHttpRequest.prototype.open;
  var origSend = XMLHttpRequest.prototype.send;
  XMLHttpRequest.prototype.open = function(method, url) {
    this.__baUrl = url;
    return origOpen.apply(this, arguments);
  };
  XMLHttpRequest.prototype.send = function() {
    var xhr = this;
    this.addEventListener('load', function() {
      try {
        if (xhr.__baUrl && GQL_RE.test(xhr.__baUrl) &&
            (xhr.responseType === '' || xhr.responseType === 'text')) {
          ingest(xhr.responseText);
        }
      } catch (_) {}
    });
    return origSend.apply(this, arguments);
  };

  /* ── Download helpers ── */
  function dl(url, filename) {
    fetch(url, { credentials: 'omit' })
      .then(function(r) { if (!r.ok) throw new Error(r.status); return r.blob(); })
      .then(function(blob) {
        var u = URL.createObjectURL(blob);
        var a = document.createElement('a');
        a.href = u;
        a.download = filename;
        document.body.appendChild(a);
        a.click();
        a.remove();
        setTimeout(function() { URL.revokeObjectURL(u); }, 5000);
      })
      .catch(function() {
        /* Cross-origin CDN without CORS — open in a new tab so the user can save. */
        window.open(url, '_blank', 'noopener');
      });
  }

  async function downloadAsZip(urls, prefix) {
    var files = [];
    for (var i = 0; i < urls.length; i++) {
      try {
        var resp = await fetch(urls[i], { credentials: 'omit' });
        if (!resp.ok) throw new Error(resp.status);
        var buf = await resp.arrayBuffer();
        var ext = 'jpg';
        var fm = urls[i].match(/format=([a-z0-9]+)/i);
        if (fm) ext = fm[1].toLowerCase();
        if (ext === 'jpeg') ext = 'jpg';
        files.push({ name: prefix + '_' + (i + 1) + '.' + ext, data: buf });
      } catch (e) {
        console.warn('[Twitter DL] fetch failed:', urls[i], e);
      }
    }
    if (files.length === 0) {
      urls.forEach(function(u) { window.open(u, '_blank', 'noopener'); });
      return;
    }
    var zipBlob = buildZip(files);
    var a = document.createElement('a');
    a.href = URL.createObjectURL(zipBlob);
    a.download = prefix + '_media.zip';
    a.click();
    URL.revokeObjectURL(a.href);
  }

  function createButton(text, onClick) {
    var btn = document.createElement('button');
    btn.className = 'ba-dl-btn';
    btn.type = 'button';
    btn.innerHTML = DL_ICON + ' ' + text;
    btn.addEventListener('click', function(e) {
      e.preventDefault();
      e.stopPropagation();
      onClick(btn);
    });
    return btn;
  }

  function getTweetId(article) {
    var links = article.querySelectorAll('a[href*="/status/"]');
    for (var i = 0; i < links.length; i++) {
      var m = (links[i].getAttribute('href') || '').match(/\/status\/(\d+)/);
      if (m) return m[1];
    }
    return null;
  }

  function imagesFromDom(article) {
    var urls = [];
    article.querySelectorAll('img').forEach(function(img) {
      var src = img.src || '';
      if (src.indexOf('twimg.com') === -1 || src.indexOf('/media/') === -1) return;
      var hi = toOrig(src);
      if (urls.indexOf(hi) === -1) urls.push(hi);
    });
    return urls;
  }

  function buildBar(article, images, videos) {
    var bar = document.createElement('div');
    bar.className = 'ba-dl-bar';

    if (images.length === 1) {
      bar.appendChild(createButton('Image', function() { dl(images[0], 'twitter_image.jpg'); }));
    } else if (images.length > 1) {
      images.forEach(function(url, idx) {
        bar.appendChild(createButton('Img ' + (idx + 1), function() {
          dl(url, 'twitter_image_' + (idx + 1) + '.jpg');
        }));
      });
      bar.appendChild(createButton('ZIP All (' + images.length + ')', function(btn) {
        var label = btn.innerHTML;
        btn.textContent = 'Packaging...';
        downloadAsZip(images, 'twitter').then(function() { btn.innerHTML = label; });
      }));
    }

    if (videos.length === 1) {
      bar.appendChild(createButton('Video', function() { dl(videos[0].url, 'twitter_video.mp4'); }));
    } else if (videos.length > 1) {
      videos.forEach(function(v, idx) {
        bar.appendChild(createButton('Video ' + (idx + 1), function() {
          dl(v.url, 'twitter_video_' + (idx + 1) + '.mp4');
        }));
      });
    }

    var group = article.querySelector('[role="group"]');
    if (group && group.parentElement) {
      group.parentElement.insertBefore(bar, group);
    } else {
      article.appendChild(bar);
    }
  }

  function processTweet(article) {
    var id = getTweetId(article);
    var captured = id ? mediaByTweet[id] : null;
    var images = (captured && captured.photos.length) ? captured.photos.slice() : imagesFromDom(article);
    var videos = (captured && captured.videos.length) ? captured.videos.slice() : [];

    /* Nothing to offer yet — if a video exists but its real URL has not been
       captured, leave the tweet unmarked so a later pass can fill it in. */
    if (images.length === 0 && videos.length === 0) return;

    var sig = (id || '?') + '|' + images.length + 'i' + videos.length + 'v';
    if (article.getAttribute(PROCESSED_ATTR) === sig) return;
    var oldBar = article.querySelector('.ba-dl-bar');
    if (oldBar) oldBar.remove();
    article.setAttribute(PROCESSED_ATTR, sig);

    buildBar(article, images, videos);
  }

  function processAll() {
    document.querySelectorAll('article[data-testid="tweet"]').forEach(processTweet);
  }

  function startDom() {
    processAll();
    var t = null;
    var observer = new MutationObserver(function() {
      if (t) clearTimeout(t);
      t = setTimeout(processAll, 400);
    });
    observer.observe(document.body, { childList: true, subtree: true });
  }

  if (document.body) startDom();
  else document.addEventListener('DOMContentLoaded', startDom);

  console.log('[Twitter/X Media Downloader] Active — buttons added to tweets; video URLs resolved from X API responses.');
})();
